import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/registry/radix-force-ui/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

const spinnerVariants = cva("animate-spin", {
  variants: {
    color: {
      default: "text-muted-foreground", // [FORCE-UI]
      primary: "text-primary", // [FORCE-UI]
      onPrimary: "text-primary-foreground", // [FORCE-UI]
      inherit: "text-current", // [FORCE-UI]
    },
    size: {
      xs: "size-3", // [FORCE-UI]
      sm: "size-4", // [FORCE-UI]
      md: "size-6", // [FORCE-UI]
      lg: "size-10", // [FORCE-UI]
    },
  },
  defaultVariants: {
    color: "default",
    size: "sm",
  },
})

function Spinner({
  className,
  color,
  size,
  ...props
}: React.ComponentProps<"svg"> & VariantProps<typeof spinnerVariants>) {
  return (
    <IconPlaceholder
      lucide="Loader2Icon"
      materialSymbols="progress_activity"
      tabler="IconLoader"
      hugeicons="Loading03Icon"
      phosphor="SpinnerIcon"
      remixicon="RiLoaderLine"
      data-slot="spinner"
      role="status"
      aria-label="Loading"
      className={cn(spinnerVariants({ color, size }), className)}
      {...props}
    />
  )
}

export { Spinner, spinnerVariants }
